import React, { useState } from "react";
import axios from "axios";

function App() {

  const [file, setFile] = useState(null);
  const [original, setOriginal] = useState(null);
  const [mask, setMask] = useState(null);
  const [highlight, setHighlight] = useState(null);

  const handleUpload = async () => {

    const formData = new FormData();
    formData.append("file", file);

    const response = await axios.post(
      "http://localhost:5000/predict",
      formData
    );

    setOriginal("data:image/png;base64," + response.data.original);
    setMask("data:image/png;base64," + response.data.mask);
    setHighlight("data:image/png;base64," + response.data.highlight);
  };

  return (
    <div style={{ textAlign: "center", marginTop: "40px" }}>

      <h1>Brain Tumor Segmentation</h1>

      <input type="file" onChange={(e) => setFile(e.target.files[0])} />
      <br /><br />
      <button onClick={handleUpload}>Predict</button>

      <div style={{
        display: "flex",
        justifyContent: "center",
        gap: "40px",
        marginTop: "40px"
      }}>

        {original && (
          <div>
            <h3>Uploaded MRI</h3>
            <img src={original} alt="original" width="220"/>
          </div>
        )}

        {mask && (
          <div>
            <h3>Tumor Mask</h3>
            <img src={mask} alt="mask" width="220"/>
          </div>
        )}

        {highlight && (
          <div>
            <h3>Tumor Highlight</h3>
            <img src={highlight} alt="highlight" width="220"/>
          </div>
        )}

      </div>

    </div>
  );
}

export default App;
